def first_unique_char(s):
    """
    Returns the index of the first character that appears exactly once in s, or -1 if none does.

    Edge case handled: An empty string returns -1.
    """
    if not s:
        return -1

    char_count = {}
    for char in s:
        if char in char_count:
            char_count[char] += 1
        else:
            char_count[char] = 1

    for index, char in enumerate(s):
        if char_count[char] == 1:
            return index

    return -1
